// src/components/TelaCaixas.jsx
import React, { useState, useEffect } from 'react'
import axios from 'axios'

export default function TelaCaixas() {
  const [caixas, setCaixas] = useState([])
  const [nome, setNome] = useState('')
  const [codigo, setCodigo] = useState('')
  const [editingId, setEditingId] = useState(null)

  useEffect(() => {
    fetchCaixas()
  }, [])

  async function fetchCaixas() {
    try {
      const { data } = await axios.get('/api/caixas')
      setCaixas(data)
    } catch (err) {
      console.error(err)
    }
  }

  async function handleSubmit(e) {
    e.preventDefault()
    try {
      if (editingId) {
        await axios.put(`/api/caixas/${editingId}`, { nome, codigo_barras: codigo })
      } else {
        await axios.post('/api/caixas', { nome, codigo_barras: codigo })
      }
      setNome('')
      setCodigo('')
      setEditingId(null)
      fetchCaixas()
    } catch (err) {
      console.error(err)
      alert(editingId ? 'Erro ao atualizar caixa' : 'Erro ao cadastrar caixa')
    }
  }

  function handleEdit(c) {
    setEditingId(c.id)
    setNome(c.nome)
    setCodigo(c.codigo_barras)
  }

  async function handleDelete(id) {
    if (!window.confirm('Tem certeza que deseja excluir esta caixa?')) return
    try {
      await axios.delete(`/api/caixas/${id}`)
      fetchCaixas()
    } catch (err) {
      console.error(err)
      alert('Erro ao excluir caixa')
    }
  }

  function handleCancel() {
    setEditingId(null)
    setNome('')
    setCodigo('')
  }

  return (
    <div className="mx-auto py-2 px-4 space-y-6">
      {/* Formulário */}
      <div className="bg-white rounded-2xl shadow p-6">
        <h2 className="text-xl font-bold mb-4">{editingId ? 'Editar Caixa' : 'Cadastrar Caixa'}</h2>
        <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <input
            className="col-span-1 md:col-span-2 border rounded px-3 py-2"
            placeholder="Nome da Caixa"
            value={nome}
            onChange={e => setNome(e.target.value)}
            required
          />
          <input
            className="border rounded px-3 py-2"
            placeholder="Código de Barras"
            value={codigo}
            onChange={e => setCodigo(e.target.value)}
            required
          />
          <div className="flex gap-2">
            <button
              type="submit"
              className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-semibold px-4 py-2 rounded-full"
            >
              {editingId ? 'Atualizar' : 'Cadastrar'}
            </button>
            {editingId && (
              <button
                type="button"
                onClick={handleCancel}
                className="flex-1 bg-gray-400 hover:bg-gray-500 text-white font-semibold px-4 py-2 rounded-full"
              >
                Cancelar
              </button>
            )}
          </div>
        </form>
      </div>

      {/* Lista de Caixas */}
      <div className="bg-white rounded-2xl shadow">
        {/* Cabeçalho (desktop) */}
        <div className="hidden md:grid md:grid-cols-4 gap-x-4 px-5 py-3 bg-gray-100 rounded-t-2xl font-semibold text-gray-600">
          <span className="truncate">ID</span>
          <span className="truncate">Nome</span>
          <span className="truncate">Código</span>
          <span className="text-right">Ações</span>
        </div>
        {/* Itens */}
        <div className="space-y-2 px-4 py-3">
          {caixas.map((c, idx) => (
            <div
              key={c.id}
              className="flex flex-col md:grid md:grid-cols-4 gap-y-2 gap-x-4 items-center bg-gray-50 rounded-xl px-4 py-3 hover:bg-gray-100 transition"
            >
              {/* ID */}
              <div className="w-full text-gray-800 truncate">{c.id}</div>
              {/* Nome */}
              <div className="w-full font-medium text-gray-800 truncate">{c.nome}</div>
              {/* Código */}
              <div className="w-full text-gray-800 truncate">{c.codigo_barras}</div>
              {/* Ações */}
              <div className="w-full flex justify-end gap-2">
                <button
                  onClick={() => handleEdit(c)}
                  className="px-3 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 text-sm font-semibold transition"
                  title="Editar"
                  type="button"
                >
                  Editar
                </button>
                <button
                  onClick={() => handleDelete(c.id)}
                  className="px-3 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 text-sm font-semibold transition"
                  title="Excluir"
                  type="button"
                >
                  Excluir
                </button>
              </div>
            </div>
          ))}
          {caixas.length === 0 && (
            <p className="text-center text-gray-500 py-4">Nenhuma caixa cadastrada.</p>
          )}
        </div>
      </div>
    </div>
  )
}
